import {useState} from 'react';import './RatingSelector.css';export default function RatingSelector(){const[r,setR]=useState(0);return <div className='card p-4 text-center'><h3>⭐ Zomato Rating</h3>{[1,2,3,4,5].map(s=><span key={s} onClick={()=>setR(s)} style={{fontSize:'40px',cursor:'pointer',color:s<=r?'gold':'gray'}}>★</span>)}<h5 className='mt-3'>Selected Rating: {r}/5</h5></div>}